/*
 * Heterogeneous Computing: CUDA Memory Management Example
 * Demonstrates: cudaMalloc, cudaMemcpy, pinned memory, CUDA streams
 */

#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>

#define N 1024
#define CHECK_CUDA(call) \
 do { \
 cudaError_t err = call; \
 if (err != cudaSuccess) { \
 fprintf(stderr, "CUDA error at %s:%d: %s\n", __FILE__, __LINE__, \
 cudaGetErrorString(err)); \
 exit(EXIT_FAILURE); \
 } \
 } while(0)

// GPU Kernel: Square each element
__global__ void squareKernel(float *d_out, float *d_in, int n) {
 int idx = blockIdx.x * blockDim.x + threadIdx.x;
 if (idx < n) {
 d_out[idx] = d_in[idx] * d_in[idx];
 }
}

// GPU Kernel: Multiply by scalar
__global__ void multiplyKernel(float *d_out, float *d_in, float scalar, int n) {
 int idx = blockIdx.x * blockDim.x + threadIdx.x;
 if (idx < n) {
 d_out[idx] = d_in[idx] * scalar;
 }
}

/*
 * Example 1: Basic Pageable Memory Transfer
 * Uses standard malloc and cudaMemcpy
 */
void basicMemoryTransfer() {
 printf("\n--- Basic Pageable Memory Transfer ---\n");

 size_t bytes = N * sizeof(float);

 // Host: Allocate pageable memory (standard malloc)
 float *h_input = (float*)malloc(bytes);
 float *h_output = (float*)malloc(bytes);

 // Initialize host input
 for (int i = 0; i < N; i++) {
 h_input[i] = (float)i;
 }
 printf("[HOST] Allocated pageable memory: %zu bytes\n", bytes);

 // Device: Allocate device memory
 float *d_input, *d_output;
 CHECK_CUDA(cudaMalloc(&d_input, bytes));
 CHECK_CUDA(cudaMalloc(&d_output, bytes));
 printf("[DEVICE] Allocated device memory\n");

 // Transfer H2D (Host to Device)
 CHECK_CUDA(cudaMemcpy(d_input, h_input, bytes, cudaMemcpyHostToDevice));
 printf("[TRANSFER] H2D: %zu bytes\n", bytes);

 // Launch kernel
 int blockSize = 256;
 int gridSize = (N + blockSize - 1) / blockSize;
 squareKernel<<<gridSize, blockSize>>>(d_output, d_input, N);
 CHECK_CUDA(cudaGetLastError());
 CHECK_CUDA(cudaDeviceSynchronize());
 printf("[DEVICE] Kernel executed\n");

 // Transfer D2H (Device to Host)
 CHECK_CUDA(cudaMemcpy(h_output, d_output, bytes, cudaMemcpyDeviceToHost));
 printf("[TRANSFER] D2H: %zu bytes\n", bytes);

 // Verify result
 printf("[RESULT] First 5 outputs: ");
 for (int i = 0; i < 5; i++) {
 printf("%.1f ", h_output[i]);
 }
 printf("\n");

 // Cleanup
 CHECK_CUDA(cudaFree(d_input));
 CHECK_CUDA(cudaFree(d_output));
 free(h_input);
 free(h_output);
 printf("[CLEANUP] Memory freed\n");
}

/*
 * Example 2: Pinned (Page-Locked) Memory
 * Uses cudaMallocHost for faster transfers and async operations
 */
void pinnedMemoryTransfer() {
 printf("\n--- Pinned Memory Transfer ---\n");

 size_t bytes = N * sizeof(float);

 // Host: Allocate pinned memory (page-locked)
 float *h_input, *h_output;
 CHECK_CUDA(cudaMallocHost(&h_input, bytes));
 CHECK_CUDA(cudaMallocHost(&h_output, bytes));

 // Initialize
 for (int i = 0; i < N; i++) {
 h_input[i] = (float)i;
 }
 printf("[HOST] Allocated pinned memory: %zu bytes\n", bytes);

 // Device memory
 float *d_input, *d_output;
 CHECK_CUDA(cudaMalloc(&d_input, bytes));
 CHECK_CUDA(cudaMalloc(&d_output, bytes));

 // Async transfer H2D
 CHECK_CUDA(cudaMemcpyAsync(d_input, h_input, bytes, cudaMemcpyHostToDevice));
 printf("[TRANSFER] Async H2D initiated\n");

 // Kernel
 int blockSize = 256;
 int gridSize = (N + blockSize - 1) / blockSize;
 squareKernel<<<gridSize, blockSize>>>(d_output, d_input, N);
 CHECK_CUDA(cudaDeviceSynchronize());

 // Async transfer D2H
 CHECK_CUDA(cudaMemcpyAsync(h_output, d_output, bytes, cudaMemcpyDeviceToHost));
 CHECK_CUDA(cudaDeviceSynchronize());
 printf("[TRANSFER] Async D2H completed\n");

 printf("[RESULT] First 5: %.1f %.1f %.1f %.1f %.1f\n",
 h_output[0], h_output[1], h_output[2], h_output[3], h_output[4]);

 // Cleanup
 CHECK_CUDA(cudaFree(d_input));
 CHECK_CUDA(cudaFree(d_output));
 CHECK_CUDA(cudaFreeHost(h_input));
 CHECK_CUDA(cudaFreeHost(h_output));
}

/*
 * Example 3: CUDA Streams for Pipelined Execution
 * Overlaps H2D transfer, kernel execution, and D2H transfer
 */
void streamPipelining() {
 printf("\n--- CUDA Streams Pipelining ---\n");

 const int numStreams = 4;
 const int segmentSize = N / numStreams;
 size_t segmentBytes = segmentSize * sizeof(float);

 // Pinned memory for all segments
 float *h_input, *h_output;
 CHECK_CUDA(cudaMallocHost(&h_input, N * sizeof(float)));
 CHECK_CUDA(cudaMallocHost(&h_output, N * sizeof(float)));

 for (int i = 0; i < N; i++) h_input[i] = (float)i;

 // Create CUDA streams
 cudaStream_t streams[numStreams];
 for (int i = 0; i < numStreams; i++) {
 CHECK_CUDA(cudaStreamCreate(&streams[i]));
 }

 printf("[STREAMS] Created %d streams for pipelining\n", numStreams);

 // Process data in segments using streams
 for (int i = 0; i < numStreams; i++) {
 float *d_input, *d_output;
 CHECK_CUDA(cudaMalloc(&d_input, segmentBytes));
 CHECK_CUDA(cudaMalloc(&d_output, segmentBytes));

 int offset = i * segmentSize;

 // Async H2D
 CHECK_CUDA(cudaMemcpyAsync(d_input, h_input + offset, segmentBytes,
 cudaMemcpyHostToDevice, streams[i]));

 // Kernel
 int gridSize = (segmentSize + 255) / 256;
 multiplyKernel<<<gridSize, 256, 0, streams[i]>>>(d_output, d_input, 2.0f, segmentSize);

 // Async D2H
 CHECK_CUDA(cudaMemcpyAsync(h_output + offset, d_output, segmentBytes,
 cudaMemcpyDeviceToHost, streams[i]));

 // Free device memory (will complete before actual free)
 CHECK_CUDA(cudaFree(d_input));
 CHECK_CUDA(cudaFree(d_output));
 }

 // Wait for all streams to complete
 for (int i = 0; i < numStreams; i++) {
 CHECK_CUDA(cudaStreamSynchronize(streams[i]));
 CHECK_CUDA(cudaStreamDestroy(streams[i]));
 }

 printf("[COMPLETE] All streams synchronized\n");
 printf("[RESULT] Sample: ");
 for (int i = 0; i < 5; i++) printf("%.1f ", h_output[i]);
 printf("\n");

 CHECK_CUDA(cudaFreeHost(h_input));
 CHECK_CUDA(cudaFreeHost(h_output));
}

int main() {
 printf("========================================\n");
 printf("CUDA Heterogeneous Computing Examples\n");
 printf("========================================\n");

 // Run all examples
 basicMemoryTransfer();
 pinnedMemoryTransfer();
 streamPipelining();

 printf("\n[SUCCESS] All examples completed\n");
 return 0;
}

/*
 * Heterogeneous Computing: Unified Memory Example
 * Demonstrates: cudaMallocManaged, cudaMemPrefetchAsync, cudaMemAdvise
 */

#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>

#define N 2048
#define CHECK_CUDA(call) \
 do { \
 cudaError_t err = call; \
 if (err != cudaSuccess) { \
 fprintf(stderr, "CUDA error at %s:%d: %s\n", __FILE__, __LINE__, \
 cudaGetErrorString(err)); \
 exit(EXIT_FAILURE); \
 } \
 } while(0)

// Kernel 1: Square elements
__global__ void squareKernel(float *data, int n) {
 int idx = blockIdx.x * blockDim.x + threadIdx.x;
 if (idx < n) {
 data[idx] = data[idx] * data[idx];
 }
}

// Kernel 2: Add constant to elements
__global__ void addKernel(float *data, float value, int n) {
 int idx = blockIdx.x * blockDim.x + threadIdx.x;
 if (idx < n) {
 data[idx] = data[idx] + value;
 }
}

// Kernel 3: Compute sum reduction (simplified)
__global__ void sumKernel(float *data, float *result, int n) {
 __shared__ float sharedData[256];

 int tid = threadIdx.x;
 int idx = blockIdx.x * blockDim.x + tid;

 // Load data into shared memory
 sharedData[tid] = (idx < n) ? data[idx] : 0.0f;
 __syncthreads();

 // Parallel reduction
 for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
 if (tid < stride) {
 sharedData[tid] += sharedData[tid + stride];
 }
 __syncthreads();
 }

 // Write block result
 if (tid == 0) {
 atomicAdd(result, sharedData[0]);
 }
}

/*
 * Example 1: Basic Unified Memory
 * Single memory space accessible from both CPU and GPU
 */
void basicUnifiedMemory() {
 printf("\n--- Basic Unified Memory ---\n");

 size_t bytes = N * sizeof(float);

 // Allocate unified memory - accessible from both CPU and GPU
 float *data;
 CHECK_CUDA(cudaMallocManaged(&data, bytes));
 printf("[UNIFIED] Allocated %zu bytes via cudaMallocManaged\n", bytes);

 // Initialize on CPU (host)
 for (int i = 0; i < N; i++) {
 data[i] = (float)(i + 1);
 }
 printf("[HOST] Initialized data on CPU\n");

 // First access from GPU triggers page migration H2D
 int blockSize = 256;
 int gridSize = (N + blockSize - 1) / blockSize;

 squareKernel<<<gridSize, blockSize>>>(data, N);
 CHECK_CUDA(cudaDeviceSynchronize());
 printf("[DEVICE] Executed square kernel - data migrated to GPU\n");

 // Access from CPU triggers page migration D2H
 printf("[HOST] First result: %.1f (migrated back to CPU)\n", data[0]);

 // Add constant on GPU
 addKernel<<<gridSize, blockSize>>>(data, 10.0f, N);
 CHECK_CUDA(cudaDeviceSynchronize());

 // Read result on CPU
 printf("[HOST] After add: data[0]=%.1f, data[1]=%.1f\n", data[0], data[1]);

 CHECK_CUDA(cudaFree(data));
}

/*
 * Example 2: Unified Memory with Prefetching
 * Proactively move data before it's needed
 */
void unifiedMemoryWithPrefetch() {
 printf("\n--- Unified Memory with Prefetching ---\n");

 size_t bytes = N * sizeof(float);
 float *data;

 // Allocate unified memory
 CHECK_CUDA(cudaMallocManaged(&data, bytes));

 // Initialize on CPU
 for (int i = 0; i < N; i++) {
 data[i] = (float)i;
 }

 // Prefetch data to GPU before kernel execution
 // cudaMemPrefetchAsync(device, bytes, stream)
 // device = cudaCpuDeviceId for CPU, or device ID for GPU
 int deviceId;
 CHECK_CUDA(cudaGetDevice(&deviceId));
 CHECK_CUDA(cudaMemPrefetchAsync(data, bytes, deviceId, 0));
 CHECK_CUDA(cudaDeviceSynchronize());
 printf("[PREFETCH] Data prefetched to GPU (device %d)\n", deviceId);

 // Execute kernel on GPU (data already there - no page fault)
 int gridSize = (N + 255) / 256;
 squareKernel<<<gridSize, 256>>>(data, N);
 CHECK_CUDA(cudaDeviceSynchronize());
 printf("[DEVICE] Kernel executed (no page fault)\n");

 // Prefetch back to CPU before reading results
 CHECK_CUDA(cudaMemPrefetchAsync(data, bytes, cudaCpuDeviceId, 0));
 CHECK_CUDA(cudaDeviceSynchronize());
 printf("[PREFETCH] Data prefetched back to CPU\n");

 printf("[HOST] Results: %.1f, %.1f, %.1f\n", data[0], data[1], data[2]);

 CHECK_CUDA(cudaFree(data));
}

/*
 * Example 3: Memory Advice for Access Patterns
 * Hint to runtime about how data will be accessed
 */
void unifiedMemoryWithAdvice() {
 printf("\n--- Unified Memory with Access Advice ---\n");

 size_t bytes = N * sizeof(float);
 float *data, *result;

 CHECK_CUDA(cudaMallocManaged(&data, bytes));
 CHECK_CUDA(cudaMallocManaged(&result, sizeof(float)));

 *result = 0.0f;

 // Initialize
 for (int i = 0; i < N; i++) {
 data[i] = 1.0f; // All ones for easy verification
 }

 // Give hints about access patterns
 // cudaMemAdviseSetReadMostly: data will be read many times
 CHECK_CUDA(cudaMemAdvise(data, bytes, cudaMemAdviseSetReadMostly, deviceId));

 // cudaMemAdviseSetPreferredLocation: prefer GPU memory
 CHECK_CUDA(cudaMemAdvise(data, bytes, cudaMemAdviseSetPreferredLocation, deviceId));

 // For result, we'll access from GPU first then CPU
 CHECK_CUDA(cudaMemAdvise(result, sizeof(float), 
 cudaMemAdviseSetPreferredLocation, deviceId));

 int deviceId_val;
 CHECK_CUDA(cudaGetDevice(&deviceId_val));
 printf("[ADVICE] Set access hints for device %d\n", deviceId_val);

 // Prefetch data to GPU
 CHECK_CUDA(cudaMemPrefetchAsync(data, bytes, deviceId_val, 0));

 // Execute reduction kernel
 sumKernel<<<1, 256>>>(data, result, N);
 CHECK_CUDA(cudaDeviceSynchronize());

 // Prefetch result to CPU
 CHECK_CUDA(cudaMemPrefetchAsync(result, sizeof(float), cudaCpuDeviceId, 0));
 CHECK_CUDA(cudaDeviceSynchronize());

 printf("[RESULT] Sum = %.1f (expected: %d.0)\n", *result, N);

 CHECK_CUDA(cudaFree(data));
 CHECK_CUDA(cudaFree(result));
}

int main() {
 printf("========================================\n");
 printf("CUDA Unified Memory Examples\n");
 printf("========================================\n");

 // Get device info
 int deviceCount;
 CHECK_CUDA(cudaGetDeviceCount(&deviceCount));
 printf("[INFO] Found %d CUDA device(s)\n", deviceCount);

 int deviceId;
 CHECK_CUDA(cudaGetDevice(&deviceId));
 printf("[INFO] Using device %d\n", deviceId);

 // Run examples
 basicUnifiedMemory();
 unifiedMemoryWithPrefetch();
 unifiedMemoryWithAdvice();

 printf("\n[SUCCESS] All unified memory examples completed\n");
 return 0;
}
